SELECT pm.role
FROM project_members pm
WHERE pm.project_id = #{projectId}
  AND pm.user_id = #{userId}

SELECT EXISTS (
    SELECT 1
    FROM project_members
    WHERE project_id = #{projectId}
      AND user_id = #{userId}
)

mapper.delete:
